import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class BankTransactionProcessor {

    private static final String DB_URL = "jdbc:mysql://localhost:3306/bank";
    private static final String USER = "user";
    private static final String PASS = "password";
    private static final Lock lock = new ReentrantLock();

    public void processTransaction(int accountId, double transactionAmount) {
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;

        try {
            conn = DriverManager.getConnection(DB_URL, USER, PASS);
            conn.setAutoCommit(false);

            lock.lock();
            try {
                // Check account balance
                String query = "SELECT balance FROM accounts WHERE account_id = ?";
                pstmt = conn.prepareStatement(query);
                pstmt.setInt(1, accountId);
                rs = pstmt.executeQuery();

                if (rs.next()) {
                    double currentBalance = rs.getDouble("balance");

                    // Validate transaction amount
                    if (currentBalance >= transactionAmount) {
                        // Update balance
                        String updateQuery = "UPDATE accounts SET balance = balance - ? WHERE account_id = ?";
                        pstmt = conn.prepareStatement(updateQuery);
                        pstmt.setDouble(1, transactionAmount);
                        pstmt.setInt(2, accountId);
                        pstmt.executeUpdate();

                        conn.commit();
                    } else {
                        System.out.println("Insufficient funds for account: " + accountId);
                    }
                }
            } finally {
                lock.unlock();
            }
        } catch (SQLException e) {
            if (conn != null) {
                try {
                    conn.rollback();
                } catch (SQLException ex) {
                    ex.printStackTrace();
                }
            }
            e.printStackTrace();
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                e.printStackTrace();
            }
        }
    }
}